import { buildFullTree, readVfsFile } from '../utils/vfs-adapter';
export const useFileSystemStore = defineStore('fileSystem', () => {
    const tree = ref([]);
    const loading = ref(false);
    const searchQuery = ref('');
    const expandedPaths = ref(new Set());
    /** 当前选中的文件/文件夹路径 */
    const selectedPath = ref(null);
    /** 当前选中的节点 */
    const selectedNode = ref(null);
    /** 是否显示操作菜单 */
    const showActionMenu = ref(false);
    async function refresh() {
        loading.value = true;
        try {
            tree.value = await buildFullTree();
        }
        catch (e) {
            console.error('[IDE] File tree refresh failed:', e);
        }
        finally {
            loading.value = false;
        }
    }
    function toggleExpand(path) {
        if (expandedPaths.value.has(path)) {
            expandedPaths.value.delete(path);
        }
        else {
            expandedPaths.value.add(path);
        }
    }
    function isExpanded(path) {
        return expandedPaths.value.has(path);
    }
    /** 选中一个节点 */
    function selectNode(node) {
        selectedPath.value = node.path;
        selectedNode.value = node;
        showActionMenu.value = true;
    }
    /** 取消选中 */
    function clearSelection() {
        showActionMenu.value = false;
    }
    const filteredTree = computed(() => {
        if (!searchQuery.value.trim())
            return tree.value;
        return filterNodes(tree.value, searchQuery.value.toLowerCase());
    });
    function filterNodes(nodes, query) {
        const result = [];
        for (const node of nodes) {
            if (node.name.toLowerCase().includes(query)) {
                result.push(node);
            }
            else if (node.children) {
                const filtered = filterNodes(node.children, query);
                if (filtered.length > 0) {
                    result.push({ ...node, children: filtered });
                }
            }
        }
        return result;
    }
    async function readFile(node) {
        if (node.type !== 'file' || !node.source)
            return null;
        return readVfsFile(node.path, node.source, node.meta);
    }
    return {
        tree,
        loading,
        searchQuery,
        expandedPaths,
        selectedPath,
        selectedNode,
        showActionMenu,
        filteredTree,
        refresh,
        toggleExpand,
        isExpanded,
        selectNode,
        clearSelection,
        readFile,
    };
});
